);

const SetRow: React.FC<{ 
  set: WorkoutSet; 
  index: number; 
  onDelete: (id: string) => void;
  onUpdate: (id: string, weight: number, reps: number, rpe: number) => void;
  onDuplicate: (set: WorkoutSet) => void;
}> = ({ set, index, onDelete, onUpdate, onDuplicate }) => {
