// --- Main App Component ---

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'log' | 'history' | 'analytics' | 'ai' | 'templates'>('log');
  const [sessions, setSessions] = useState<WorkoutSession[]>([]);
  const [templates, setTemplates] = useState<WorkoutTemplate[]>([]);
  const [currentSession, setCurrentSession] = useState<WorkoutSession | null>(null);
  const [isExerciseModalOpen, setIsExerciseModalOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [aiInsights, setAiInsights] = useState<string>('');
  const [isLoadingAi, setIsLoadingAi] = useState(false);

  const [settings, setSettings] = useState({
    theme: 'dark' as 'light' | 'dark',
    units: 'kg' as 'kg' | 'lb',
    accent: 'emerald'
  });

  // Timer states
  const [exerciseTimer, setExerciseTimer] = useState<number | null>(null);
  const [workoutStopwatch, setWorkoutStopwatch] = useState<number>(0);

  const timerRef = useRef<NodeJS.Timeout | null>(null);
  const stopwatchRef = useRef<NodeJS.Timeout | null>(null);

  // Persistence
  useEffect(() => {
    const savedSessions = localStorage.getItem('vibelift_sessions');
    if (savedSessions) setSessions(JSON.parse(savedSessions));

    const savedTemplates = localStorage.getItem('vibelift_templates');
    if (savedTemplates) setTemplates(JSON.parse(savedTemplates));

    const savedSettings = localStorage.getItem('vibelift_settings');
    if (savedSettings) setSettings(JSON.parse(savedSettings));
  }, []);

  useEffect(() => {
    localStorage.setItem('vibelift_sessions', JSON.stringify(sessions));
  }, [sessions]);

  useEffect(() => {
    localStorage.setItem('vibelift_templates', JSON.stringify(templates));
  }, [templates]);

  useEffect(() => {
    localStorage.setItem('vibelift_settings', JSON.stringify(settings));
    // Apply theme
    if (settings.theme === 'light') {
      document.documentElement.classList.remove('dark');
    } else {
      document.documentElement.classList.add('dark');
    }
  }, [settings]);

  // Exercise Timer logic
  useEffect(() => {
    if (exerciseTimer !== null && exerciseTimer > 0) {
      timerRef.current = setTimeout(() => setExerciseTimer(exerciseTimer - 1), 1000);
    } else if (exerciseTimer === 0) {
      setExerciseTimer(null);
    }
    return () => { if (timerRef.current) clearTimeout(timerRef.current); };
  }, [exerciseTimer]);

  // Stopwatch logic
  useEffect(() => {
    if (currentSession && !currentSession.endTime) {
      stopwatchRef.current = setInterval(() => {
        setWorkoutStopwatch(prev => prev + 1);
      }, 1000);
    } else {
      if (stopwatchRef.current) clearInterval(stopwatchRef.current);
    }
    return () => { if (stopwatchRef.current) clearInterval(stopwatchRef.current); };
  }, [currentSession]);

  const startWorkout = (template?: WorkoutTemplate) => {
    const newSession: WorkoutSession = {
      id: Date.now().toString(),
      name: template ? template.name : 'Quick Workout',
      startTime: new Date().toISOString(),
      exercises: template ? template.exerciseIds.map(eid => ({
        exerciseId: eid,
        sets: [{ id: Math.random().toString(), weight: 0, reps: 0, rpe: 8, completedAt: new Date().toISOString() }]
      })) : []
    };
    setCurrentSession(newSession);
    setWorkoutStopwatch(0);
    setActiveTab('log');
  };

  const finishWorkout = () => {
    if (currentSession) {
      const completedSession = { ...currentSession, endTime: new Date().toISOString() };
      setSessions([completedSession, ...sessions]);
      setCurrentSession(null);
      setExerciseTimer(null);
      setWorkoutStopwatch(0);
    }
  };

  const deleteSession = (sessionId: string) => {
    setSessions(prev => prev.filter(s => s.id !== sessionId));
  };

  const addExerciseToWorkout = (exercise: Exercise) => {
    if (!currentSession) return;
    const newLogged: LoggedExercise = {
      exerciseId: exercise.id,
      sets: [{ id: Math.random().toString(), weight: 0, reps: 0, rpe: 8, completedAt: new Date().toISOString() }]
    };
    setCurrentSession({
      ...currentSession,
      exercises: [...currentSession.exercises, newLogged]
    });
    setIsExerciseModalOpen(false);
  };

  const triggerExerciseTimer = () => {
    setExerciseTimer(60); // Reset to 60s rest on set completion
  };

  const addSetToExercise = (exerciseId: string, setDefaults?: Partial<WorkoutSet>) => {
    if (!currentSession) return;
    const exerciseLogs = currentSession.exercises.find(e => e.exerciseId === exerciseId);
    const lastSet = exerciseLogs?.sets.slice(-1)[0];

    const newSet: WorkoutSet = {
      id: Math.random().toString(),
      weight: setDefaults?.weight ?? lastSet?.weight ?? 0,
      reps: setDefaults?.reps ?? lastSet?.reps ?? 0,
      rpe: setDefaults?.rpe ?? lastSet?.rpe ?? 8,
      completedAt: new Date().toISOString()
    };

    setCurrentSession({
      ...currentSession,
      exercises: currentSession.exercises.map(e => 
        e.exerciseId === exerciseId ? { ...e, sets: [...e.sets, newSet] } : e
      )
    });
    triggerExerciseTimer();
  };

  const updateSet = (exerciseId: string, setId: string, weight: number, reps: number, rpe: number) => {
    if (!currentSession) return;

    // Check for Personal Best in history
    const allMatchingSets = sessions.flatMap(s => s.exercises)
      .filter(ex => ex.exerciseId === exerciseId)
      .flatMap(ex => ex.sets);
    const maxWeight = Math.max(...allMatchingSets.map(s => s.weight), 0);
    const isPB = weight > maxWeight && weight > 0;

    setCurrentSession({
      ...currentSession,
      exercises: currentSession.exercises.map(e => 
        e.exerciseId === exerciseId ? {
          ...e,
          sets: e.sets.map(s => s.id === setId ? { ...s, weight, reps, rpe, isPB } : s)
        } : e
      )
    });
    // Reseting timer when updating weight/reps as well (assumes marking off set)
    if (weight > 0 && reps > 0) triggerExerciseTimer();
  };

  const deleteSet = (exerciseId: string, setId: string) => {
    if (!currentSession) return;
    setCurrentSession({
      ...currentSession,
      exercises: currentSession.exercises.map(e => 
        e.exerciseId === exerciseId ? {
          ...e,
          sets: e.sets.filter(s => s.id !== setId)
        } : e
      )
    });
  };

  const getGhostSession = (exerciseId: string) => {
    for (const session of sessions) {
      const matchingEx = session.exercises.find(e => e.exerciseId === exerciseId);
      if (matchingEx && matchingEx.sets.length > 0) {
        return matchingEx.sets;
      }
    }
    return null;
  };

  const getRecommendation = (sets: WorkoutSet[]) => {
    if (sets.length === 0) return null;
    const last = sets[sets.length - 1];
    if (last.weight === 0 || last.reps === 0) return null;

    if (last.rpe <= 7) return { text: `Up weight (+2.5${settings.units})`, color: `text-${settings.accent}-500` };
    if (last.rpe >= 10) return { text: "Decrease load", color: "text-red-400" };
    return { text: "Maintain intensity", color: "text-zinc-500" };
  };

  const handleGenerateInsights = async () => {
    setIsLoadingAi(true);
    const result = await getWorkoutInsights(sessions);
    setAiInsights(result || '');
    setIsLoadingAi(false);
  };

  const chartData = useMemo(() => {
    const dailyVolume: Record<string, number> = {};
    sessions.forEach(s => {
      const date = new Date(s.startTime).toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
      const vol = s.exercises.reduce((acc, ex) => acc + ex.sets.reduce((setAcc, set) => setAcc + (set.weight * set.reps), 0), 0);
      dailyVolume[date] = (dailyVolume[date] || 0) + vol;
    });
    return Object.entries(dailyVolume).map(([date, volume]) => ({ date, volume })).reverse();
  }, [sessions]);

  // --- UI Render Sections ---

  const renderLog = () => {
    if (!currentSession) {
      return (
        <div className="flex flex-col items-center justify-center h-full p-8 space-y-6">
          <div className={`p-6 bg-zinc-100 dark:bg-zinc-900 rounded-full border border-zinc-200 dark:border-zinc-800 shadow-2xl transition-all duration-500`}>
            <Dumbbell size={64} className={`text-${settings.accent}-500 animate-pulse`} />
          </div>
          <div className="text-center">
            <h2 className="text-2xl font-extrabold tracking-tight text-zinc-900 dark:text-zinc-100">VIBE LIFT</h2>
            <p className="text-zinc-500 text-sm max-w-[240px] mt-1">Consistency is king. Start a session now.</p>
          </div>
          <div className="w-full max-w-[280px] space-y-3">
            <button 
              onClick={() => startWorkout()}
              className={`w-full bg-${settings.accent}-500 hover:opacity-90 text-white font-black py-4 rounded-xl flex items-center justify-center space-x-2 transition-transform active:scale-95 shadow-xl`}
            >
              <Play size={20} fill="currentColor" />
              <span>START EMPTY</span>
            </button>
            <button 
              onClick={() => setActiveTab('templates')}
              className="w-full bg-zinc-100 dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-800 text-zinc-900 dark:text-white font-bold py-4 rounded-xl flex items-center justify-center space-x-2 transition-transform active:scale-95"
            >
              <Layout size={20} />
              <span>ROUTINES</span>
            </button>
          </div>
        </div>
      );
    }

    return (
      <div className="p-4 pb-32 space-y-6 overflow-y-auto h-full">
        {/* Lockscreen Timers Display */}
        <div className="bg-zinc-100 dark:bg-zinc-900/60 backdrop-blur-xl border border-zinc-200 dark:border-zinc-800 rounded-3xl p-4 flex justify-between items-center shadow-lg transition-all sticky top-2 z-40">
           <div className="flex items-center space-x-4">
             <div className="flex flex-col">
               <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest leading-none mb-1">Workout</span>
               <span className="text-xl font-black font-mono leading-none text-zinc-900 dark:text-zinc-100">{formatTime(workoutStopwatch)}</span>
             </div>
             <div className="h-8 w-[1px] bg-zinc-200 dark:bg-zinc-800"></div>
             <div className="flex flex-col">
               <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest leading-none mb-1">Rest</span>
               <span className={`text-xl font-black font-mono leading-none ${exerciseTimer !== null ? `text-${settings.accent}-500` : 'text-zinc-400'}`}>
                 {exerciseTimer !== null ? `${exerciseTimer}s` : '--:--'}
               </span>
             </div>
           </div>
           <button 
              onClick={finishWorkout}
              className={`text-white font-black text-sm bg-${settings.accent}-500 px-6 py-2 rounded-xl shadow-lg active:scale-95 transition-all`}
            >
              FINISH
            </button>
        </div>

        <div className="flex justify-between items-center mb-4 pt-2">
          <div className="flex flex-col">
            <span className="text-xs font-bold text-zinc-500 uppercase">{currentSession.name}</span>
            <span className="text-sm font-mono text-zinc-400">SESSION ID: {currentSession.id.slice(-6)}</span>
          </div>
          <button 
              onClick={() => {
                const name = prompt("Routine Name:", currentSession.name);
                if(name) setTemplates([...templates, { id: Date.now().toString(), name, exerciseIds: currentSession.exercises.map(e => e.exerciseId) }]);
              }}
              className="p-2 bg-zinc-100 dark:bg-zinc-800 rounded-lg text-zinc-500 hover:text-white"
            >
              <Save size={18} />
          </button>
        </div>

        {currentSession.exercises.map((log) => {
          const exercise = EXERCISE_LIBRARY.find(e => e.id === log.exerciseId);
          const ghostSets = getGhostSession(log.exerciseId);
          const recommendation = getRecommendation(log.sets);

          return (
            <div key={log.exerciseId} className="bg-white dark:bg-zinc-900 border border-zinc-100 dark:border-zinc-800 rounded-3xl overflow-hidden shadow-xl transition-all">
              <div className="p-4 border-b border-zinc-100 dark:border-zinc-800 flex justify-between items-center bg-zinc-50 dark:bg-zinc-800/20">
                <div className="flex-1">
                  <h3 className="font-bold text-lg leading-tight text-zinc-900 dark:text-zinc-100">{exercise?.name}</h3>
                  <div className="flex items-center space-x-2 mt-1">
                    <span className="text-[10px] uppercase tracking-tighter text-zinc-500 bg-zinc-100 dark:bg-zinc-800 px-2 py-0.5 rounded font-bold">{exercise?.muscleGroup}</span>
                    {recommendation && (
                      <span className={`text-[10px] font-black uppercase ${recommendation.color}`}>{recommendation.text}</span>
                    )}
                  </div>
                </div>
                <button 
                  onClick={() => addSetToExercise(log.exerciseId)}
                  className={`p-2 bg-${settings.accent}-500 text-white rounded-xl shadow-lg hover:opacity-90 active:scale-90 transition-all`}
                >
                  <Plus size={20} />
                </button>
              </div>

              {ghostSets && (
                <div className="px-4 py-2 bg-zinc-50 dark:bg-zinc-950/50 border-b border-zinc-100 dark:border-zinc-800">
                  <div className="flex items-center space-x-1 mb-1">
                    <History size={10} className="text-zinc-500" />
                    <span className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest">Ghost Session Data</span>
                  </div>
                  <div className="flex space-x-4">
                    {ghostSets.slice(0, 2).map((gs, i) => (
                      <div key={gs.id} className="text-[10px] text-zinc-400 font-mono">
                        Set {i+1}: <span className="text-zinc-700 dark:text-zinc-200 font-bold">{gs.weight}{settings.units} x {gs.reps}</span>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              <div className="p-3">
                <div className="grid grid-cols-6 gap-2 px-3 mb-2 text-[10px] font-black text-zinc-400 uppercase tracking-[0.2em]">
                  <div>Set</div>
                  <div className="text-center">Load</div>
                  <div className="text-center">Reps</div>
                  <div className="text-center">RPE</div>
                  <div className="text-center"></div>
                  <div className="text-center"></div>
                </div>
                {log.sets.map((set, idx) => (
                  <SetRow 
                    key={set.id} 
                    set={set} 
                    index={idx} 
                    units={settings.units}
                    onDelete={(id) => deleteSet(log.exerciseId, id)}
                    onUpdate={(id, w, r, rp) => updateSet(log.exerciseId, id, w, r, rp)}
                    onDuplicate={(s) => addSetToExercise(log.exerciseId, { weight: s.weight, reps: s.reps, rpe: s.rpe })}
                  />
                ))}
              </div>
            </div>
          );
        })}

        <button 
          onClick={() => setIsExerciseModalOpen(true)}
          className="w-full border-2 border-dashed border-zinc-200 dark:border-zinc-800 rounded-3xl p-8 text-zinc-400 hover:text-zinc-600 dark:hover:text-zinc-300 hover:border-zinc-300 dark:hover:border-zinc-700 transition-all flex flex-col items-center justify-center space-y-2"
        >
          <Plus size={24} />
          <span className="text-sm font-black uppercase tracking-widest">Add Exercise</span>
        </button>
      </div>
    );
  };

  const renderHistory = () => (
    <div className="p-4 space-y-4 pb-24 h-full overflow-y-auto">
      <h2 className="text-xl font-black text-zinc-900 dark:text-zinc-100 uppercase tracking-tight">Recent Activity</h2>
      {sessions.length === 0 ? (
        <div className="text-center py-20 text-zinc-500 italic">No workouts logged yet.</div>
      ) : (
        sessions.map(s => (
          <div key={s.id} className="bg-white dark:bg-zinc-900 border border-zinc-100 dark:border-zinc-800 rounded-3xl p-5 relative group hover:border-zinc-200 dark:hover:border-zinc-700 transition-all shadow-md">
            <button 
              onClick={() => deleteSession(s.id)}
              className="absolute top-4 right-4 text-zinc-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity"
            >
              <Trash2 size={16} />
            </button>
            <div className="flex items-center space-x-2 mb-1">
              <span className="text-xs font-bold text-zinc-400 uppercase tracking-widest">{new Date(s.startTime).toLocaleDateString('en-GB', { day: 'numeric', month: 'short' })}</span>
              <span className="w-1 h-1 rounded-full bg-zinc-200 dark:bg-zinc-800" />
              <span className="text-xs font-bold text-zinc-400">{new Date(s.startTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
            </div>
            <h3 className="font-black text-xl mb-3 tracking-tight text-zinc-900 dark:text-zinc-100">{s.name || 'Strength Session'}</h3>
            <div className="flex flex-wrap gap-2">
              {s.exercises.map(ex => {
                const info = EXERCISE_LIBRARY.find(e => e.id === ex.exerciseId);
                return (
                  <span key={ex.exerciseId} className="text-[10px] bg-zinc-50 dark:bg-zinc-800 border border-zinc-100 dark:border-zinc-700 text-zinc-500 dark:text-zinc-300 px-2 py-1 rounded font-bold uppercase tracking-tighter">
                    {info?.name} <span className={`text-${settings.accent}-500 ml-1`}>{ex.sets.length}S</span>
                  </span>
                );
              })}
            </div>
          </div>
        ))
      )}
    </div>
  );

  const renderAnalytics = () => (
    <div className="p-4 space-y-6 pb-24 h-full overflow-y-auto">
      <h2 className="text-xl font-black text-zinc-900 dark:text-zinc-100 uppercase tracking-tight">Performance</h2>

      <div className="bg-white dark:bg-zinc-900 border border-zinc-100 dark:border-zinc-800 rounded-3xl p-6 h-72 shadow-xl">
        <div className="flex justify-between items-start mb-6">
          <h4 className="text-[10px] font-black text-zinc-400 uppercase tracking-widest">Tonnage (kg) Progression</h4>
          <div className={`bg-${settings.accent}-500/10 text-${settings.accent}-500 text-[10px] px-2 py-1 rounded font-black`}>VOLUME</div>
        </div>
        <ResponsiveContainer width="100%" height="80%">
          <AreaChart data={chartData}>
            <defs>
              <linearGradient id="colorVol" x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor={ACCENT_COLORS.find(c => c.value === settings.accent)?.hex} stopOpacity={0.3}/>
                <stop offset="95%" stopColor={ACCENT_COLORS.find(c => c.value === settings.accent)?.hex} stopOpacity={0}/>
              </linearGradient>
            </defs>
            <CartesianGrid strokeDasharray="3 3" stroke="#27272a" vertical={false} opacity={0.1} />
            <XAxis dataKey="date" stroke="#52525b" fontSize={10} tickLine={false} axisLine={false} />
            <YAxis hide />
            <Tooltip 
              contentStyle={{ backgroundColor: settings.theme === 'dark' ? '#09090b' : '#ffffff', border: '1px solid #27272a', borderRadius: '12px', fontSize: '12px' }}
              itemStyle={{ color: ACCENT_COLORS.find(c => c.value === settings.accent)?.hex, fontWeight: 'bold' }}
              cursor={{ stroke: '#52525b', strokeWidth: 1 }}
            />
            <Area type="monotone" dataKey="volume" stroke={ACCENT_COLORS.find(c => c.value === settings.accent)?.hex} fillOpacity={1} fill="url(#colorVol)" strokeWidth={3} />
          </AreaChart>
        </ResponsiveContainer>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div className="bg-white dark:bg-zinc-900 border border-zinc-100 dark:border-zinc-800 rounded-3xl p-5 shadow-md">
          <div className="text-[10px] text-zinc-400 font-bold uppercase tracking-widest mb-2">Total Sets</div>
          <div className={`text-3xl font-black text-${settings.accent}-500 tabular-nums`}>
            {sessions.reduce((acc, s) => acc + s.exercises.reduce((exAcc, ex) => exAcc + ex.sets.length, 0), 0)}
          </div>
        </div>
        <div className="bg-white dark:bg-zinc-900 border border-zinc-100 dark:border-zinc-800 rounded-3xl p-5 shadow-md">
          <div className="text-[10px] text-zinc-400 font-bold uppercase tracking-widest mb-2">PBs Hit</div>
          <div className="text-3xl font-black text-blue-500 dark:text-blue-400 tabular-nums">
            {sessions.reduce((acc, s) => acc + s.exercises.reduce((exAcc, ex) => exAcc + ex.sets.filter(st => st.isPB).length, 0), 0)}
          </div>
        </div>
      </div>
    </div>
  );

  const renderAI = () => (
    <div className="p-4 space-y-6 pb-24 h-full overflow-y-auto">
      <div className={`bg-gradient-to-br from-${settings.accent}-600/30 to-blue-600/30 p-8 rounded-[2.5rem] border border-white/10 relative overflow-hidden shadow-2xl`}>
        <div className="relative z-10 space-y-6">
          <div className="flex items-center space-x-3">
            <div className="p-3 bg-white rounded-2xl text-black shadow-xl">
               <Zap size={24} fill="currentColor" />
            </div>
            <h2 className="text-3xl font-black tracking-tighter text-white">AI COACH</h2>
          </div>
          <p className="text-white/80 text-sm leading-relaxed font-medium">
            Personalized strategy based on your load patterns, RPE history, and recovery needs.
          </p>
          <button 
            onClick={handleGenerateInsights}
            disabled={isLoadingAi || sessions.length === 0}
            className="w-full bg-white text-black font-black py-4 rounded-2xl flex items-center justify-center space-x-2 active:scale-95 transition-all disabled:opacity-50 hover:bg-zinc-100 shadow-xl"
          >
            {isLoadingAi ? <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-black"></div> : 'GENERATE STRATEGY'}
          </button>
        </div>
        <div className="absolute -right-16 -bottom-16 opacity-10 pointer-events-none text-white">
          <Zap size={300} />
        </div>
      </div>

      {aiInsights && (
        <div className="bg-white dark:bg-zinc-900 border border-zinc-100 dark:border-zinc-800 rounded-[2rem] p-6 space-y-6 shadow-xl">
          <h4 className="text-[10px] font-black text-zinc-400 uppercase tracking-[0.2em] border-b border-zinc-50 dark:border-zinc-800 pb-3">Training Protocol</h4>
          <div className="space-y-5 text-zinc-800 dark:text-zinc-200">
            {aiInsights.split('\n').map((line, i) => (
              <div key={i} className="flex space-x-4 group">
                <div className={`mt-1.5 w-2 h-2 rounded-full bg-${settings.accent}-500 flex-shrink-0 group-hover:scale-125 transition-transform shadow-lg`} />
                <p className="text-sm leading-relaxed font-medium">{line.replace(/^[*-]\s*/, '')}</p>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );

  return (
    <div className={`flex flex-col h-screen ${settings.theme === 'dark' ? 'bg-zinc-950' : 'bg-zinc-50'} text-zinc-900 dark:text-zinc-50 max-w-md mx-auto relative shadow-2xl overflow-hidden font-inter border-x border-zinc-100 dark:border-zinc-900 transition-colors duration-300`}>
      {/* Header */}
      <header className={`p-4 pt-8 flex justify-between items-center ${settings.theme === 'dark' ? 'bg-zinc-950/80' : 'bg-white/80'} backdrop-blur-md z-20 sticky top-0`}>
        <div className="flex items-center space-x-2">
          <div className={`w-9 h-9 bg-${settings.accent}-500 rounded-xl flex items-center justify-center shadow-lg`}>
            <Zap size={20} className="text-white" fill="currentColor" />
          </div>
          <h1 className="text-2xl font-black tracking-tighter italic text-zinc-900 dark:text-zinc-100 uppercase">VIBE<span className={`text-${settings.accent}-500`}>LIFT</span></h1>
        </div>
        <button 
          onClick={() => setIsSettingsOpen(true)}
          className="p-2 text-zinc-500 hover:text-zinc-900 dark:hover:text-zinc-100 bg-zinc-100 dark:bg-zinc-900 rounded-lg transition-colors"
        >
          <SettingsIcon size={20} />
        </button>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 overflow-hidden relative">
        {activeTab === 'log' && renderLog()}
        {activeTab === 'history' && renderHistory()}
        {activeTab === 'analytics' && renderAnalytics()}
        {activeTab === 'ai' && renderAI()}
        {activeTab === 'templates' && (
           <div className="p-4 space-y-6 pb-24 h-full overflow-y-auto">
              <div className="flex justify-between items-center">
                <h2 className="text-xl font-black text-zinc-900 dark:text-zinc-100 uppercase tracking-tight">Routines</h2>
                <button onClick={() => setIsExerciseModalOpen(true)} className={`p-2 bg-zinc-100 dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-800 rounded-lg text-${settings.accent}-500`}>
                  <Plus size={20} />
                </button>
              </div>
              {templates.map(t => (
                <div key={t.id} className="bg-white dark:bg-zinc-900 border border-zinc-100 dark:border-zinc-800 rounded-3xl p-5 flex justify-between items-center hover:border-zinc-300 dark:hover:border-zinc-700 transition-all shadow-md">
                   <div>
                      <h3 className="font-bold text-lg text-zinc-900 dark:text-zinc-100">{t.name}</h3>
                      <p className="text-xs text-zinc-500">{t.exerciseIds.length} exercises</p>
                   </div>
                   <div className="flex space-x-2">
                      <button onClick={() => setTemplates(templates.filter(temp => temp.id !== t.id))} className="p-3 text-zinc-300 hover:text-red-500"><Trash2 size={20}/></button>
                      <button onClick={() => startWorkout(t)} className={`p-3 bg-${settings.accent}-500 text-white rounded-2xl shadow-lg active:scale-95 transition-all`}><Play size={20} fill="currentColor"/></button>
                   </div>
                </div>
              ))}
           </div>
        )}
      </main>

      {/* Modals */}
      <SettingsModal 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)} 
        settings={settings}
        onUpdate={(k, v) => setSettings(prev => ({ ...prev, [k]: v }))}
      />

      {isExerciseModalOpen && (
        <div className="fixed inset-0 z-50 bg-black/80 backdrop-blur-md flex items-end sm:items-center justify-center p-0 sm:p-4">
          <div className="bg-white dark:bg-zinc-900 w-full max-w-md h-[85vh] rounded-t-[2.5rem] sm:rounded-3xl border border-zinc-200 dark:border-zinc-800 flex flex-col overflow-hidden animate-in slide-in-from-bottom duration-300 shadow-2xl">
            <div className="p-6 border-b border-zinc-100 dark:border-zinc-800 flex justify-between items-center">
              <h3 className="font-black text-xl tracking-tight text-zinc-900 dark:text-zinc-100 uppercase">Library</h3>
              <button onClick={() => setIsExerciseModalOpen(false)} className="p-3 bg-zinc-100 dark:bg-zinc-800 rounded-xl text-zinc-500 hover:text-zinc-900 dark:hover:text-white"><X /></button>
            </div>
            <div className="p-4 space-y-2 overflow-y-auto">
              {EXERCISE_LIBRARY.map(ex => (
                <button 
                  key={ex.id}
                  onClick={() => addExerciseToWorkout(ex)}
                  className="w-full text-left p-5 bg-zinc-50 dark:bg-zinc-800/40 hover:bg-zinc-100 dark:hover:bg-zinc-800 rounded-2xl transition-all border border-transparent hover:border-zinc-200 dark:hover:border-zinc-700 flex justify-between items-center group"
                >
                  <div>
                    <div className={`font-black text-zinc-900 dark:text-zinc-100 group-hover:text-${settings.accent}-500 transition-colors`}>{ex.name}</div>
                    <div className="text-[10px] text-zinc-500 uppercase font-bold tracking-widest mt-1">{ex.muscleGroup}</div>
                  </div>
                  <ChevronRight size={18} className="text-zinc-400 group-hover:text-zinc-600 dark:group-hover:text-zinc-100 transition-colors" />
                </button>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* Bottom Navigation */}
      <nav className={`fixed bottom-0 left-0 right-0 ${settings.theme === 'dark' ? 'bg-zinc-900/95' : 'bg-white/95'} backdrop-blur-xl border-t border-zinc-100 dark:border-zinc-800 h-24 px-6 flex justify-between items-center z-30 max-w-md mx-auto shadow-2xl`}>
        <NavItem icon={<Dumbbell size={24} />} label="Log" active={activeTab === 'log'} accent={settings.accent} onClick={() => setActiveTab('log')} />
        <NavItem icon={<Layout size={24} />} label="Routines" active={activeTab === 'templates'} accent={settings.accent} onClick={() => setActiveTab('templates')} />
        <NavItem icon={<History size={24} />} label="History" active={activeTab === 'history'} accent={settings.accent} onClick={() => setActiveTab('history')} />
        <NavItem icon={<BarChart2 size={24} />} label="Analytics" active={activeTab === 'analytics'} accent={settings.accent} onClick={() => setActiveTab('analytics')} />
        <NavItem icon={<Zap size={24} />} label="AI" active={activeTab === 'ai'} accent={settings.accent} onClick={() => setActiveTab('ai')} />
      </nav>
    </div>
  );
};

export default App;

